E2Helper.Descriptions["sendLuaString(s)"] = "Sends a Lua string via Player:SendLua(). Limited to 255 characters."
E2Helper.Descriptions["sendLongLuaString(s)"] = "Sends a Lua string via the net library. Limited to 65535 characters."
E2Helper.Descriptions["sendLongLuaString(sf)"] = "Sends a Lua string via the net library. Limited to 65535 characters. Runs a callback with the Lua's return values as an array."
